(function(){"use strict";const e=document.getElementById("marketQuotes");if(!e)return;async function t(){try{const e=await fetch("/daily-news/market-data.json");if(!e.ok)return;const t=await e.json();n(t)}catch{e.innerHTML='<p style="font-size:12px;color:#999;">行情加载失败</p>'}}function n(t){if(!t||!t.indices){e.innerHTML='<p style="font-size:12px;color:#999;">暂无数据</p>';return}const n=t.indices.map(e=>{const t=e.change>=0?"up":"down",n=e.change>=0?`+${e.change.toFixed(2)}%`:`${e.change.toFixed(2)}%`;return`
                <div class="market-item">
                    <span class="name">${e.name}</span>
                    <span class="change ${t}">${n}</span>
                </div>
            `}).join("");e.innerHTML=n}t()})()